import { createWorkflow, Step } from 'mastra/workflows';
import { z } from 'zod';

const researchStep: Step = {
  name: 'research',
  inputSchema: z.object({ topic: z.string(), brandGuidelines: z.string() }),
  tools: [webSearchTool],
  llmPrompt: `Research {topic} following {brandGuidelines}`
};

const draftStep: Step = {
  name: 'draft',
  inputSchema: z.object({ research: z.string(), guidelines: z.string() }),
  llmPrompt: `Write 800-word article using {research}. Enforce {guidelines}`
};

export const contentWorkflow = createWorkflow({
  name: 'content-generation',
  steps: [researchStep, draftStep],
  outputSchema: z.object({
    title: z.string(),
    body: z.string(),
    seoKeywords: z.array(z.string())
  })
});

import { tool } from 'mastra/tools';
import { cosineSimilarity } from 'ai-embeddings';

const BRAND_VOICE_EXAMPLES = [
  'Crisp, professional tone with actionable insights',
  'Optimistic language focusing on customer success'
];

export const brandVoiceChecker = tool({
  name: 'brand_voice_check',
  description: 'Score content against brand voice guidelines',
  inputSchema: z.object({
    content: z.string(),
    guidelines: z.string().optional()
  }),
  execute: async ({ content, guidelines }) => {
    const embeddings = await getEmbeddings([content, ...BRAND_VOICE_EXAMPLES]);
    const score = cosineSimilarity(embeddings[0], embeddings.slice(1));

    return {
      score: Math.max(...score),
      passed: score > 0.85,
      suggestions: score < 0.85 ? ['Use more active voice', 'Add customer success examples'] : []
    };
  }
});

import { tool } from 'mastra/tools';

export const factChecker = tool({
  name: 'fact_check',
  description: 'Verify factual claims with source citations',
  inputSchema: z.object({
    claims: z.array(z.object({
      claim: z.string(),
      context: z.string()
    }))
  }),
  execute: async ({ claims }) => {
    const results = await Promise.all(
      claims.map(async ({ claim, context }) => {
        const sources = await searchAuthoritativeSources(claim);
        const verified = sources.some(source => 
          source.relevance > 0.9 && source.content.includes(claim)
        );

        return {
          claim,
          verified,
          sources: sources.slice(0, 3),
          confidence: verified ? 'high' : 'low'
        };
      })
    );

    return {
      overallAccuracy: results.filter(r => r.verified).length / claims.length,
      failedClaims: results.filter(r => !r.verified),
      citations: results.flatMap(r => r.sources)
    };
  }
});

import { tool } from 'mastra/tools';

export const seoValidator = tool({
  name: 'seo_validate',
  description: 'Validate SEO compliance and keyword optimization',
  inputSchema: z.object({
    content: z.string(),
    targetKeywords: z.array(z.string()),
    targetLength: z.number().optional()
  }),
  execute: async ({ content, targetKeywords, targetLength = 800 }) => {
    const wordCount = content.split(' ').length;
    const keywordDensity = targetKeywords.map(kw => 
      (content.toLowerCase().split(kw.toLowerCase()).length - 1) / wordCount
    );

    const issues = [];
    if (wordCount < targetLength * 0.8) {
      issues.push(`Content too short: ${wordCount}/${targetLength} words`);
    }

    const keywordScores = targetKeywords.map((kw, i) => ({
      keyword: kw,
      density: keywordDensity[i],
      optimal: keywordDensity[i] > 0.01 && keywordDensity[i] < 0.03
    }));

    return {
      passed: issues.length === 0 && keywordScores.every(s => s.optimal),
      wordCount,
      keywordScores,
      issues
    };
  }
});

