import { Vex } from '@vex_dev/sdk';
import { contentWorkflow } from './workflows';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY!,
  projectId: 'content-gen-mastra'
});

export async function verifiedContentGeneration(input: any) {
  // Step 1: Research with fact validation
  const researchOutput = await contentWorkflow.execute('research', input);
  const validatedResearch = await vex.verify({
    data: researchOutput,
    checks: ['factual_accuracy'],
    context: { stage: 'research', topic: input.topic }
  });

  // Step 2: Drafting with structure validation
  const draftOutput = await contentWorkflow.execute('draft', {
    ...input,
    research: validatedResearch
  });

  const validatedDraft = await vex.verify({
    data: draftOutput,
    checks: ['brand_consistency', 'tone_adherence'],
    context: { stage: 'drafting', guidelines: input.brandGuidelines }
  });

  return validatedDraft;
}

import { Vex } from '@vex_dev/sdk';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY! });

// Register content-specific verifiers
await vex.registerVerifiers([
  {
    name: 'brand_consistency',
    type: 'semantic_similarity',
    threshold: 0.85,
    reference: process.env.BRAND_VOICE_CORPUS_URL!,
    description: 'Ensure content matches brand voice guidelines'
  },
  {
    name: 'factual_accuracy',
    type: 'fact_check',
    sources: ['wikipedia', 'official_stats'],
    confidenceThreshold: 0.9
  },
  {
    name: 'seo_compliance',
    type: 'regex_multi',
    patterns: [
      { name: 'keyword_density', regex: /targetKeyword/g, min: 1, max: 3 },
      { name: 'h1_present', regex: /<h1>/ }
    ]
  },
  {
    name: 'originality',
    type: 'plagiarism_check',
    threshold: 0.05
  }
]);

import { Vex } from '@vex_dev/sdk';
import { AgentExecutor } from 'mastra';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY! });

const monitoredAgent = new AgentExecutor({
  agent: contentAgent,
  tools: [brandVoiceChecker, factChecker, seoValidator],
  middleware: [
    {
      name: 'vex-guardrails',
      async beforeCall(context) {
        const span = await vex.startSpan({
          name: `mastra-${context.stepName}`,
          metadata: { workflow: 'content-gen', input: context.input }
        });
        return { ...context, vexSpan: span };
      },
      async afterCall(context, result) {
        const verified = await vex.verify({
          data: result,
          spanId: context.vexSpan.id,
          checks: ['brand_consistency', 'factual_accuracy']
        });

        if (!verified.passed) {
          throw new Error(`Vex validation failed: ${verified.issues.join(', ')}`);
        }

        await vex.endSpan(context.vexSpan.id, { passed: true });
        return verified.data;
      }
    }
  ]
});
